import { Avatar } from '@material-ui/core'
import React from 'react'
import {  NavLink } from 'react-router-dom'
import styled from 'styled-components'
import logo from '../images/codmitu.svg'

export default function Navbar() {
    return (
        <Container>
            <Logo src={logo} alt="codmitu"/>

            <Wrapper> 
                <Ul>
                    <Li>
                        <Div>
                            <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" exact={true}  to="">acasă</NavLink>
                        </Div>
                    </Li>
                    <Li>
                        <Div>
                            <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" to="cumpara">cumpără</NavLink>
                        </Div>
                    </Li>
                    <Li>
                        <Div>
                            <NavLink onClick={() => window.scrollTo(0, 0)} activeClassName="active" to="login">login</NavLink>
                        </Div>
                    </Li>
                </Ul>

                <MyAvatar src="" alt="avatar" />
            </Wrapper>
        </Container>
    )
}



const Container = styled.nav`
    width: 100%;
    height: 100px;
    background: linear-gradient(135deg, #3123ae8d 0%, #53a0fe8b 50%, #b3ed5088 100%);
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-family: var(--fsss);
    box-shadow: 0 3px 6px rgba(0,0,0,0.16), 0 3px 6px rgba(0,0,0,0.23);
`
const Logo = styled.img`
    height: 70px;
    margin: 0 20px;
    pointer-events: none;
`
const Wrapper = styled.section`
    display: flex;
    align-items: center;
    margin: 0 20px;
`
const Ul = styled.ul`
    display: flex;
    align-items: center;
    padding: 0;
    @media screen and (max-width: 600px) {
        display: none;
    }
`
const Li = styled.li`
    list-style: none;
    width: 100px;
    height: 100px;
    display: grid;
    place-content: center;
`
const Div = styled.div`
    border-radius: 50%;
    padding: 2px;
    width: 30px;
    height: 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: var(--cyl);
    transition: background-color 0.5s ease-in-out, border-radius 0.3s ease-in-out 0.3s, width 0.3s ease-in-out 0.3s;
    &:hover {
        background-color: var(--crl);
        width: 90px;
        border-radius: 10px;
        animation: bounce 2s both;
        @keyframes bounce { 
            0%, 20%, 50%, 80%, 100% {
                transform: translateY(0);
            } 
            40% {
                transform: translateY(-5px);
            } 
            60% {
                transform: translateY(-2px);
            } 
        }
    }
    >a {
        color: black;
        text-decoration: none;
        &:hover {
            color: white;
        }
        &.active {
            color: var(--crl);
            &:hover {
                color: white;
            }
        }
    }
`
const MyAvatar = styled(Avatar)`
    cursor: pointer;
    border: 1px solid var(--cbl);
    margin-left: 20px;
`