import { Button } from '@material-ui/core'
import React from 'react'
import styled from 'styled-components'
import ShoppingBasketIcon from '@material-ui/icons/ShoppingBasket';
import video from '../../video/video.mkv'
import illustration from '../../images/illustration.svg'
import Bubbles from '../../components/Bubbles';
import AboutSection from '../../components/AboutSection';
import { useRef } from 'react';

export default function Homepage() {

    return (
        <Container >
            <Bubbles />

            <WelcomeSection>
                <Left>
                    <H2>Site-uri, pagini web, bloguri pentru desktop și mobil</H2>
                    <H1>Site-ul <b>tău</b> ● reclama mea</H1>
                    <P>Programator <b>Front-End</b>, mă ocup cu schițarea și construirea de website-uri, site-uri e-commerce cu bază de date și autentificare Google. Încă la început de drum în acest domeniu pun suflet și pasiune în fiecare proiect.</P>
                    <Button variant="contained" size="small" endIcon={<ShoppingBasketIcon/>}>cumpără</Button>
                </Left>

                <Right>
                    <Video src={video}  type="video/mkv" controls autoPlay muted loop></Video>
                    <Illustration src={illustration} alt="illustration" />
                </Right>
            </WelcomeSection>

            <AboutSection/>
        </Container>
    )
}


const Container = styled.main`
    min-height: 300vh;
    padding: 0 5vw;
    display: grid;
    place-content: center;
    position: relative;
    overflow: hidden;
    `
const WelcomeSection = styled.div`
    min-height: calc(100vh - 100px);
    position: relative;
    z-index: 1;
    display: flex;
    margin: 0 auto;
    max-width: 1500px;
    gap: 10vw; 
    pointer-events: none;
    @media screen and (max-width: 1000px) {
        flex-direction: column;
    }
`
const Left = styled.article`
    flex: 1;
    margin: 100px 0 0;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    >button {
        border-radius: 10px;
        background: linear-gradient(125deg, var(--crd), var(--crl));
        color: white;
        font-family: var(--fsss);
        margin-top: 20px;
        padding: 10px 20px;
        pointer-events: all;
        &:hover {
            background: linear-gradient(125deg, var(--crl), var(--crl));
            animation: bounce 2s both;
            @keyframes bounce { 
                0%, 20%, 50%, 80%, 100% {
                    transform: translateY(0);
                } 
                40% {
                    transform: translateY(-5px);
                } 
                60% {
                    transform: translateY(-2px);
                } 
            }
        }
    }
    @media screen and (max-width: 900px) {
        text-align: center;
        align-items: center;
    }
`
const H2 = styled.h2`
    font-size: var(--mf);
    font-family: var(--fsss);
    font-weight: 200;
    color: grey;
    line-height: 1;
`
const H1 = styled.h1`
    font-size: var(--bf);
    font-family: var(--fsss);
    color: #2e2e2e;
    font-weight: 500;
    line-height: 1;
    margin-top: var(--sf);
    margin-bottom: var(--bf);
    >b {
        color: var(--cbd);
    }
`
const P = styled.p`
    font-size: var(--sf);
    line-height: 1.6;
    >b {
        color: var(--cbl);
    }
`
const Right = styled.article`
    flex: 1;
    display: grid;
    place-content: center;
    position: relative;
`
const Video = styled.video`
    object-fit: contain;
    width: calc(100% - 20px);
    box-shadow: 0 19px 38px rgba(0,0,0,0.30), 0 15px 32px rgba(0,0,0,0.22);
    pointer-events: all;
    border: 10px solid black;
    border-radius: 10px;
    @media screen and (max-width: 1000px) {
        max-height: 30vh;
    }
`
const Illustration = styled.img`
    position: absolute;
    bottom: 50%;
    left: 50%;
    object-fit: contain;
    transform: translate(-50%, 50%);
    width: 120%;
    pointer-events: none;
    @media screen and (max-width: 1000px) {
        max-height: 30vh;
        bottom: 40%;
    }
`