import React from 'react'
import { useMemo } from 'react'
import { createRef } from 'react'
import styled from 'styled-components'
import Bubble from './Bubble'
import Bubble2 from './Bubble2'

export default function Bubbles({refr}) {
    const bubbleRef = useMemo(() => Array(50).fill(0).map(i => createRef()), [])
    const bubbleRef2 = useMemo(() => Array(50).fill(0).map(i => createRef()), [])


    return (
        <Container>
            {new Array(50).fill(0).map((bubble, i) => (
                <Bubble  key={i} refr={bubbleRef[i]}/>
            ))}
            {new Array(50).fill(0).map((bubble, i) => (
                <Bubble2  key={i} refr={bubbleRef2[i]}/>
            ))}
        </Container>
    )
}


const Container = styled.section`
    height: 100%;
    position: absolute;
    inset: 0;
`
